CODE_EXAMPLE:
// Before (smell - adding a field requires changing many classes)
class Order { String currency; }
class Invoice { String currency; }
class Payment { String currency; }
class Receipt { String currency; }

// After (refactored)
class CurrencySettings {
  String currency;
  // Only this class changes when currency logic changes
}

class Order { CurrencySettings currencySettings; }
class Invoice { CurrencySettings currencySettings; }

UNIT_TEST_EXAMPLE:
@Test
public void testShotgunSurgery() {
  CurrencySettings settings = new CurrencySettings("USD");
  Order order = new Order(settings);
  assertEquals("USD", order.getCurrencySettings().getCurrency());
}
